const rows = items[0]?.json || [];
const summary = {
  telegram_sent: 0,
  telegram_failed: 0,
  email_sent: 0,
  email_failed: 0,
};
const errors = {};

for (const row of rows) {
  if (row.channel === 'whatsapp' && row.status === 'sent') summary.telegram_sent += 1;
  if (row.channel === 'whatsapp' && row.status === 'failed') summary.telegram_failed += 1;
  if (row.channel === 'email' && row.status === 'sent') summary.email_sent += 1;
  if (row.channel === 'email' && row.status === 'failed') summary.email_failed += 1;

  if (row.status === 'failed') {
    const key = row.error_message || 'erro_desconhecido';
    errors[key] = (errors[key] || 0) + 1;
  }
}

const top_erros = Object.entries(errors)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([message, count]) => `${message} (${count})`)
  .join('\n') || 'Sem falhas nas ultimas 24h';

return [{ json: { ...summary, top_erros } }];
